import{c as t,Q as r,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Chain of Thought — 2026-05-24","description":"","frontmatter":{"title":"Chain of Thought — 2026-05-24","date":"2026-05-24T00:00:00.000Z","source":"Chain of Thought","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-24-chain-of-thought.md","filePath":"research/ai-news/2026-05/2026-05-24-chain-of-thought.md","lastUpdated":1779894392000}'),n={name:"research/ai-news/2026-05/2026-05-24-chain-of-thought.md"};function i(h,e,s,l,p,d){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="⛓️-chain-of-thought-—-2026-05-24" tabindex="-1">⛓️ Chain of Thought — 2026-05-24 <a class="header-anchor" href="#⛓️-chain-of-thought-—-2026-05-24" aria-label="Permalink to &quot;⛓️ Chain of Thought — 2026-05-24&quot;">​</a></h1><blockquote><p>Dan Shipper（Every.to）的 AI 與策略 / 社會交點深度週報 來源：<a href="https://every.to/chain-of-thought/feed.xml" target="_blank" rel="noreferrer">Chain of Thought</a></p></blockquote><hr><h2 id="inside-anthropic-s-2026-developer-conference" tabindex="-1"><a href="https://every.to/chain-of-thought/inside-anthropic-s-2026-developer-conference" target="_blank" rel="noreferrer">Inside Anthropic’s 2026 Developer Conference</a> <a class="header-anchor" href="#inside-anthropic-s-2026-developer-conference" aria-label="Permalink to &quot;[Inside Anthropic’s 2026 Developer Conference](https://every.to/chain-of-thought/inside-anthropic-s-2026-developer-conference)&quot;">​</a></h2><p><em>⛓️ Chain of Thought</em></p><p>by <a href="https://every.to/@danshipper" target="_blank" rel="noreferrer">Dan Shipper</a>, <a href="https://every.to/@marcus_fd8302_1" target="_blank" rel="noreferrer">Marcus Moretti</a>, and <a href="https://every.to/@katie.parrott12" target="_blank" rel="noreferrer">Katie Parrott</a>in <a href="https://every.to/chain-of-thought" target="_blank" rel="noreferrer">Chain of Thought</a>Midjourney/Every illustration. Was this newsletter forwarded to you? <a href="https://every.to/account" target="_blank" rel="noreferrer">Sign up</a> to get it in your inbox.</p><p>To our surprise, the biggest launch from Anthropic’s <a href="https://claude.com/code-with-claude" target="_blank" rel="noreferrer">developer conference</a> in San Francisco yesterday wasn’t a model or a feature. Instead, it was the company’s announcement of <a href="https://www.anthropic.com/news/higher-limits-spacex" target="_blank" rel="noreferrer">a deal with SpaceX</a> to allocate all of the capacity in the latter’s Colossus supercluster to Claude.</p><p>Anthropic has been riding a historic demand surge over the last year as Claude Code opened up a new wave of agentic coding for engineers and non-engineers alike. But compute constraints have caused friction even amongst its most die-hard fans—we’ve written previously about <a href="https://every.to/context-window/get-your-hands-dirty#signal" target="_blank" rel="noreferrer">being frustrated</a> with its OpenClaw restrictions and the speed of its latest models like <a href="https://every.to/vibe-check/opus-4-7" target="_blank" rel="noreferrer">Opus 4.7</a>.</p><p>The deal with SpaceX changes that equation. Anthropic has already doubled rate limits for subscription plans, removed peak-hour limits on Pro and Max accounts, and raised API rate limits by as much as almost 17 times for certain tiers.</p><p>Other than that, the big story is Claude Managed Agents, Anthropic’s hosted agent product. The company released <a href="https://claude.com/blog/new-in-claude-managed-agents" target="_blank" rel="noreferrer">three new features</a>:</p><p>Multi-agent orchestration: a coordinator agent that spins up subagents in parallel baked into the platform</p><p>Dreaming: Anthropic’s general-purpose version of <a href="https://every.to/guides/compound-engineering" target="_blank" rel="noreferrer">compound engineering</a>, a feature that allows agents to learn from past sessions to improve between runs</p><p>Outcomes: Anthropic’s answer to Codex’s /goals command, allowing developers to specify an outcome and run an agent in a loop until the outcome is achieved</p><p>By themselves, these features are nice but not groundbreaking. What’s more important is that what an AI platform is has changed. In the GPT-3 days, the platform was a text completion end-point: Send text in, get text out. Now, with Claude Managed Agents, the platform is an AI model with a harness and host computer—all provided with unlimited scaling by the model companies.</p><p><a href="https://cora.computer" target="_blank" rel="noreferrer">Cora</a> general manager <a href="https://every.to/@kieran_1355" target="_blank" rel="noreferrer">Kieran Klaassen</a> and I reported live from conference with our biggest takeaways, including the xAI compute deal, doubled Claude usage limits, Claude Managed Agents, and why the battle lines between OpenAI and Anthropic are starting to become clearer. Watch now:</p><p>[</p><p>](<a href="https://www.youtube.com/watch?v=4YNHb0XNV1A" target="_blank" rel="noreferrer">https://www.youtube.com/watch?v=4YNHb0XNV1A</a>)</p><p>We also recorded a conversation with Angela Jiang, head of product for the Claude platform, and Katelyn Lesse, head of platform engineering. The full episode drops tomorrow on <a href="https://every.to/podcast" target="_blank" rel="noreferrer">AI &amp; I</a>—highlights below.—<a href="https://every.to/@danshipper" target="_blank" rel="noreferrer">Dan Shipper</a></p><p>Vibe Check: Claude Managed Agents</p><p>Spiral general manager Marcus Moretti uses the platform’s new features</p><p>Anthropic launched Claude Managed Agents in April, and since then, Every’s AI writing tool <a href="https://writewithspiral.com/" target="_blank" rel="noreferrer">Spiral</a> has used the platform to power its API and command line interface (CLI), which lets developers and other agents talk to Spiral outside the web app. Claude Managed Agents run on Anthropic’s servers, instead of us having to run them on our own.</p><p>We set up a new Managed Agent in an afternoon and <a href="https://every.to/context-window/the-missing-layer-in-ai-adoption#spiral-is-experimenting-with-agent-to-agent-workflows" target="_blank" rel="noreferrer">deployed it to power our API</a> the next day. We’ve incorporated two of the new features Anthropic announced yesterday (memory and multi-agent orchestration) and are deploying the third (outcomes) soon.</p><p>Memory: Every’s editorial and social expertise—how to write a good X post, for example—lives in...</p><p>Become a <a href="https://every.to/subscribe" target="_blank" rel="noreferrer">paid subscriber to Every</a> to unlock this piece and learn about:</p><p>How Spiral is already using the new features announced this week</p><p>How Claude’s new “Dreaming” feature takes a page out of compound engineering</p><p>Why Anthropic says building a model-agnostic harness is a losing strategy</p><p><a href="https://every.to/subscribe?source=post_button" target="_blank" rel="noreferrer">Subscribe</a></p><p><a href="https://every.to/chain-of-thought/inside-anthropic-s-2026-developer-conference" target="_blank" rel="noreferrer">Click here</a> to read the full post</p><p>Want the full text of all articles in RSS? <a href="https://every.to/subscribe" target="_blank" rel="noreferrer">Become a subscriber</a>, or <a href="https://every.to" target="_blank" rel="noreferrer">learn more</a>.</p><hr><h2 id="when-your-vibe-coded-app-goes-viral—and-then-goes-down" tabindex="-1"><a href="https://every.to/chain-of-thought/when-your-vibe-coded-app-goes-viral-and-then-goes-down" target="_blank" rel="noreferrer">When Your Vibe Coded App Goes Viral—And Then Goes Down</a> <a class="header-anchor" href="#when-your-vibe-coded-app-goes-viral—and-then-goes-down" aria-label="Permalink to &quot;[When Your Vibe Coded App Goes Viral—And Then Goes Down](https://every.to/chain-of-thought/when-your-vibe-coded-app-goes-viral-and-then-goes-down)&quot;">​</a></h2><p><em>⛓️ Chain of Thought</em></p><p>by <a href="https://every.to/@danshipper" target="_blank" rel="noreferrer">Dan Shipper</a>in <a href="https://every.to/chain-of-thought" target="_blank" rel="noreferrer">Chain of Thought</a>Midjourney/Every illustration. Was this newsletter forwarded to you?<a href="https://every.to/account" target="_blank" rel="noreferrer"></a><a href="https://every.to/account" target="_blank" rel="noreferrer">Sign up</a> to get it in your inbox.</p><p>At 4 a.m. on the day after we launched our <a href="https://every.to/guides/agent-native" target="_blank" rel="noreferrer">agent-native</a> document editor, <a href="https://proofeditor.ai" target="_blank" rel="noreferrer">Proof</a>, I watched yet another <a href="https://every.to/vibe-check/codex-vibe-check" target="_blank" rel="noreferrer">Codex</a> agent try to revive our server.</p><p>Over 4,000 documents had been created since launch, but the app had been mysteriously crashing all day. This left users with crucial documents that they couldn’t access, and me with egg on my face.</p><p>I hadn’t slept for almost 24 hours, and all I could do was nervously munch trail mix as Codex investigated yet another bug buried deep in a codebase that I didn’t understand. It felt less like programming and more like being the dumbest participant at a math Olympiad. Needless to say, I was reconsidering my life choices.</p><p>Today, almost a week later, Proof is more or less stable. And I’ve learned a lot about both building and launching a purely vibe coded app. Perhaps more importantly, I’ve also learned what happens once that app goes live—and then goes down.</p><p>My current opinion is this: If you can vibe code it, you can vibe fix it. You just might not be able to fix it quickly.</p><p>Software engineering is changing rapidly as a discipline. The days of typing code into a computer manually seem to be over, and the current conversation on X is around “zero-human startups.” My experience with Proof, though, is a good reality check.</p><p>It demonstrates both what is truly possible with vibe coded apps, and where human engineers will continue to be critical now and in the future.</p><p>What’s possible at the edge</p><p>I’ve been writing about how AI is changing programming <a href="https://every.to/chain-of-thought/i-spent-24-hours-with-github-copilot-workspaces" target="_blank" rel="noreferrer">for a few years now</a>, and my experience with Proof confirms a lot of my thoughts...</p><p>Become a <a href="https://every.to/subscribe" target="_blank" rel="noreferrer">paid subscriber to Every</a> to unlock this piece and learn about:</p><p>What it took to bring a crashing, vibe coded app back from the brink</p><p>The specific failure modes coding models keep hitting</p><p>Why allocation is the new key skill for human engineers</p><p><a href="https://every.to/subscribe?source=post_button" target="_blank" rel="noreferrer">Subscribe</a></p><p><a href="https://every.to/chain-of-thought/when-your-vibe-coded-app-goes-viral-and-then-goes-down" target="_blank" rel="noreferrer">Click here</a> to read the full post</p><p>Want the full text of all articles in RSS? <a href="https://every.to/subscribe" target="_blank" rel="noreferrer">Become a subscriber</a>, or <a href="https://every.to" target="_blank" rel="noreferrer">learn more</a>.</p><hr><h2 id="the-two-slice-team" tabindex="-1"><a href="https://every.to/chain-of-thought/the-two-slice-team" target="_blank" rel="noreferrer">The Two-slice Team</a> <a class="header-anchor" href="#the-two-slice-team" aria-label="Permalink to &quot;[The Two-slice Team](https://every.to/chain-of-thought/the-two-slice-team)&quot;">​</a></h2><p><em>⛓️ Chain of Thought</em></p><p>by <a href="https://every.to/@danshipper" target="_blank" rel="noreferrer">Dan Shipper</a>in <a href="https://every.to/chain-of-thought" target="_blank" rel="noreferrer">Chain of Thought</a>Midjourney/Every illustration. ​​TLDR: Today we’re launching a new experiment: Proof, an agent-native markdown editor that lets you collaborate on documents with multiple humans and AI agents—and tracks who wrote what. It’s available now for paid Every subscribers.</p><p>Try Proof</p><p>For the past two decades, Amazon’s “two-pizza rule” has been the gold standard for team size.</p><p>The story goes like this: At a company retreat in 2002, when Amazon managers wanted more communication, Jeff Bezos fired back that “communication is terrible!” A few weeks later, he restructured the company around small autonomous teams. If a team had more than 10 people—more than could be fed by two pizzas—it was too big.</p><p>Twenty-four years later, two-pizza teams are now themselves too big for building software products. When each employee is armed with Opus 4.6 and Codex 5.3, the ideal team size shrinks even further.</p><p><a href="https://every.to/chain-of-thought/the-two-slice-team" target="_blank" rel="noreferrer">Click here</a> to read the full post</p><p>Want the full text of all articles in RSS? <a href="https://every.to/subscribe" target="_blank" rel="noreferrer">Become a subscriber</a>, or <a href="https://every.to" target="_blank" rel="noreferrer">learn more</a>.</p><hr><h2 id="openai-has-some-catching-up-to-do" tabindex="-1"><a href="https://every.to/chain-of-thought/openai-has-some-catching-up-to-do" target="_blank" rel="noreferrer">OpenAI Has Some Catching Up to Do</a> <a class="header-anchor" href="#openai-has-some-catching-up-to-do" aria-label="Permalink to &quot;[OpenAI Has Some Catching Up to Do](https://every.to/chain-of-thought/openai-has-some-catching-up-to-do)&quot;">​</a></h2><p><em>⛓️ Chain of Thought</em></p><p>by <a href="https://every.to/@danshipper" target="_blank" rel="noreferrer">Dan Shipper</a>in <a href="https://every.to/chain-of-thought" target="_blank" rel="noreferrer">Chain of Thought</a>Midjourney / Every Illustration. Was this newsletter forwarded to you? <a href="https://every.to/account" target="_blank" rel="noreferrer">Sign up</a> to get it in your inbox.</p><p>This morning I hit my usage limit on <a href="https://every.to/vibe-check/gpt-5-codex-knows-when-to-think-hard-and-when-not-to" target="_blank" rel="noreferrer">Codex</a>, OpenAI’s competitor to Claude Code. I’m building an <a href="https://every.to/guides/agent-native" target="_blank" rel="noreferrer">agent-native</a> Markdown editor for the Every team. It’s exactly the kind of complex, detail-heavy project where Codex shines.</p><p>But this week was an exception. Most of my coding happens in Claude Code now—and I’m not alone.</p><p>On Tuesday night, we had about 20 founders over to the office for a dinner on the future of AI. I asked everyone what their daily driver AI tools were. Of the programmers, almost everyone said Claude Code with Opus 4.5. The lone holdout was <a href="https://every.to/@naveen_6804" target="_blank" rel="noreferrer">Naveen Naidu</a>—general manager of <a href="https://www.monologue.to" target="_blank" rel="noreferrer">Monologue</a>—who still prefers Codex.</p><p>A month ago, the room would have been split between Codex CLI, GPT 5.1 in Cursor, and Claude Code—with some <a href="https://every.to/vibe-check/vibe-check-i-canceled-two-ai-max-plans-for-factory-s-coding-agent-droid" target="_blank" rel="noreferrer">Droid</a> sprinkled in.</p><p>A year ago, the whole room would have been using GPT models.</p><p>This might not surprise you if you’ve been on X lately. It seems the only thing on everyone’s mind is Claude Code. This audience is obviously a narrow slice of the market, but it’s <a href="https://every.to/p/ai-can-build-anything-social-dandelions-decide-what-spreads" target="_blank" rel="noreferrer">the same slice</a> that was excited about ChatGPT when it first came out.</p><p>So, what explains Claude Code and Opus’s sudden rise in startup circles? It’s not better marketing. Sure, Anthropic has their <a href="https://www.instagram.com/p/DPW0CJQkmAq/" target="_blank" rel="noreferrer">“thinking” caps</a>. But compared to the high-profile livestreams we’ve gotten used to for important model releases, they barely promoted <a href="https://every.to/vibe-check/vibe-check-opus-4-5-is-the-coding-model-we-ve-been-waiting-for" target="_blank" rel="noreferrer">Opus 4.5</a> at launch. Instead, it’s who they decided to build for—and how that’s shaping the direction of the whole tech industry.</p><p>How Claude Code happened</p><p>When Anthropic first released Claude Code along with Sonnet 3.7 in late February of 2025, it was a bold bet. At a time when existing code editors were firmly stuck in building AI agents crammed into a sidebar, they went terminal-first and bypassed the code editor altogether. It signaled, “We’re moving to a world where code doesn’t matter.” At the time, we <a href="https://every.to/vibe-check/vibe-check-claude-3-7-sonnet-and-claude-code" target="_blank" rel="noreferrer">wrote</a> that while it was incredible at vibe coding new projects from scratch, it wasn’t yet good enough to work with large codebases on its own. Still, we were impressed.</p><p>Become a <a href="https://every.to/subscribe" target="_blank" rel="noreferrer">paid subscriber to Every</a> to unlock this piece and learn about:</p><p>The dramatic shift in AI tool preferences among startup founders—and why nearly everyone has abandoned what they used a year ago</p><p>Why OpenAI’s bet on professional developers may be targeting a market that’s about to shrink</p><p>The unexpected reason the winner of “vibe coding” might determine how everyone works on computers</p><p><a href="https://every.to/subscribe?source=post_button" target="_blank" rel="noreferrer">Subscribe</a></p><p><a href="https://every.to/chain-of-thought/openai-has-some-catching-up-to-do" target="_blank" rel="noreferrer">Click here</a> to read the full post</p><p>Want the full text of all articles in RSS? <a href="https://every.to/subscribe" target="_blank" rel="noreferrer">Become a subscriber</a>, or <a href="https://every.to" target="_blank" rel="noreferrer">learn more</a>.</p><hr><h2 id="agent-native-architectures-how-to-build-apps-after-the-end-of-code" tabindex="-1"><a href="https://every.to/chain-of-thought/agent-native-architectures-how-to-build-apps-after-the-end-of-code" target="_blank" rel="noreferrer">Agent-native Architectures: How to Build Apps After the End of Code</a> <a class="header-anchor" href="#agent-native-architectures-how-to-build-apps-after-the-end-of-code" aria-label="Permalink to &quot;[Agent-native Architectures: How to Build Apps After the End of Code](https://every.to/chain-of-thought/agent-native-architectures-how-to-build-apps-after-the-end-of-code)&quot;">​</a></h2><p><em>⛓️ Chain of Thought</em></p><p>by <a href="https://every.to/@danshipper" target="_blank" rel="noreferrer">Dan Shipper</a>in <a href="https://every.to/chain-of-thought" target="_blank" rel="noreferrer">Chain of Thought</a>Midjourney/Every illustration. Was this newsletter forwarded to you? Sign up to get it in your inbox. Plus: Help us scale the only subscription you need to stay at the edge of AI. Explore open roles at Every.</p><p>Traditional software is built like a skyscraper.</p><p>Any application you use daily—whether it’s Word, Figma, or Gmail—is a bronze and glass facade towering 500 feet above the street. It is a lobby with travertine walls that smells faintly of sandalwood. Every beam is load-tested. Every force and flow obeys the blueprint.</p><p>Just to be real with you, I am jealous of architects. I often moonlight as one, but as a programmer, my skyscrapers are shoddy. I start before the blueprint is final; I dig a foundation and sink some beams, but they are usually off by an eighth of an inch. By the time we get to the fifth story, I need a real architect to take over.</p><p>But AI enables a new kind of software, one that’s more like growing a garden than it is building a skyscraper. I’ve been calling it an agent-native architecture—and we’ve pivoted our whole software strategy at Every around it.</p><p>The core of an agent-native architecture is not code. Instead, as the name implies, the core is an agent—something squishy and alive, planted in sun and soil. Each feature of the app is a prompt to the agent that names the result to achieve, not a set of steps to follow. That’s why I often think of agent-native apps as Claude Code in a trenchcoat.</p><p><a href="https://every.to/chain-of-thought/agent-native-architectures-how-to-build-apps-after-the-end-of-code" target="_blank" rel="noreferrer">Click here</a> to read the full post</p><p>Want the full text of all articles in RSS? <a href="https://every.to/subscribe" target="_blank" rel="noreferrer">Become a subscriber</a>, or <a href="https://every.to" target="_blank" rel="noreferrer">learn more</a>.</p><hr>',92)])])}const f=t(n,[["render",i]]);export{u as __pageData,f as default};
